  const [stats, setStats] = useState({ original: 0, minified: 0, saved: 0 });
  const [isMinifying, setIsMinifying] = useState(false);
  const { copyToClipboard, copied } = useClipboard();

  useSEO({
    title: "JavaScript Minifier Online | Compress JS Code",
