import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Slider } from "@/components/ui/slider";
import { Shuffle } from "lucide-react";
import { useSEO } from "@/lib/seo";
import { CodePreviewCard } from "@/components/tools/CodePreviewCard";

export default function GradientGenerator() {
  useSEO({
    title: "CSS Gradient Generator | Create Beautiful Backgrounds",
    description: "Create linear & radial gradients visually and copy CSS instantly. Works offline.",
    keywords: "css gradient generator, gradient maker, background generator, linear gradient",
    canonicalUrl: "https://tools.pixocraft.in/tools/gradient-generator",
  });

  const [type, setType] = useState<"linear" | "radial">("linear");
  const [angle, setAngle] = useState(90);
  const [color1, setColor1] = useState("#3B82F6");
  const [color2, setColor2] = useState("#8B5CF6");

  const generateCSS = () => {
    if (type === "linear") {
      return `background: linear-gradient(${angle}deg, ${color1}, ${color2});`;
    } else {
      return `background: radial-gradient(circle, ${color1}, ${color2});`;
    }
  };

  const randomize = () => {
    const randomColor = () => "#" + Math.floor(Math.random() * 16777215).toString(16).padStart(6, "0");
    setColor1(randomColor());
    setColor2(randomColor());
    setAngle(Math.floor(Math.random() * 360));
  };

  const gradientStyle = {
    background: type === "linear"
      ? `linear-gradient(${angle}deg, ${color1}, ${color2})`
      : `radial-gradient(circle, ${color1}, ${color2})`,
  };

  return (
    <div className="min-h-screen py-20">
      <div className="container mx-auto px-4 max-w-6xl">
        <div className="text-center space-y-4 mb-12">
          <h1 className="text-4xl md:text-5xl font-bold">CSS Gradient Generator</h1>
          <p className="text-xl text-muted-foreground max-w-2xl mx-auto">
            Create beautiful gradients visually and copy CSS in one click. Perfect for developers & designers.
          </p>
        </div>

        <div className="grid gap-8 lg:grid-cols-2">
          <div className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Gradient Settings</CardTitle>
                <CardDescription>Customize your gradient</CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="space-y-2">
                  <Label>Gradient Type</Label>
                  <Select value={type} onValueChange={(v) => setType(v as "linear" | "radial")}>
                    <SelectTrigger data-testid="select-type">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="linear">Linear</SelectItem>
                      <SelectItem value="radial">Radial</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                {type === "linear" && (
                  <div className="space-y-2">
                    <Label>Angle: {angle}°</Label>
                    <Slider
                      value={[angle]}
                      onValueChange={([v]) => setAngle(v)}
                      min={0}
                      max={360}
                      step={1}
                      data-testid="slider-angle"
                    />
                  </div>
                )}

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="color1">Color 1</Label>
                    <div className="flex gap-2">
                      <Input
                        id="color1"
                        type="color"
                        value={color1}
                        onChange={(e) => setColor1(e.target.value)}
                        className="h-10 w-16"
                        data-testid="input-color1"
                      />
                      <Input
                        value={color1}
                        onChange={(e) => setColor1(e.target.value)}
                        placeholder="#3B82F6"
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="color2">Color 2</Label>
                    <div className="flex gap-2">
                      <Input
                        id="color2"
                        type="color"
                        value={color2}
                        onChange={(e) => setColor2(e.target.value)}
                        className="h-10 w-16"
                        data-testid="input-color2"
                      />
                      <Input
                        value={color2}
                        onChange={(e) => setColor2(e.target.value)}
                        placeholder="#8B5CF6"
                      />
                    </div>
                  </div>
                </div>

                <Button onClick={randomize} variant="outline" className="w-full" data-testid="button-randomize">
                  <Shuffle className="mr-2 h-4 w-4" />
                  Randomize
                </Button>
              </CardContent>
            </Card>

            <CodePreviewCard title="CSS Code" code={generateCSS()} />
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Preview</CardTitle>
              <CardDescription>See your gradient in action</CardDescription>
            </CardHeader>
            <CardContent>
              <div
                className="w-full h-96 rounded-lg border-2 border-border"
                style={gradientStyle}
                data-testid="preview-gradient"
              />
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

client/src/components/SearchDialog.tsx.content:
import { useState, useEffect } from "react";
import { useLocation } from "wouter";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { tools, getToolIcon } from "@/lib/tools";
import { Search, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useSearch } from "@/contexts/SearchContext";

export function SearchDialog() {
  const { isOpen, closeSearch } = useSearch();
  const [, setLocation] = useLocation();
  const [searchQuery, setSearchQuery] = useState("");
  const [filteredTools, setFilteredTools] = useState(tools);

  useEffect(() => {
    if (!searchQuery.trim()) {
      setFilteredTools(tools);
      return;
    }

    const query = searchQuery.toLowerCase();
    const filtered = tools.filter((tool) => {
      const matchesName = tool.name.toLowerCase().includes(query);
      const matchesDescription = tool.description.toLowerCase().includes(query);
      const matchesKeywords = tool.keywords.some((keyword) =>
        keyword.toLowerCase().includes(query)
      );
      const matchesCategory = tool.category.toLowerCase().includes(query);

      return matchesName || matchesDescription || matchesKeywords || matchesCategory;
    });

    setFilteredTools(filtered);
  }, [searchQuery]);

  const handleToolSelect = (toolPath: string) => {
    setLocation(toolPath);
    closeSearch();
    setSearchQuery("");
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && filteredTools.length > 0) {
      handleToolSelect(filteredTools[0].path);
    }
  };

  const handleOpenChange = (open: boolean) => {
    if (!open) {
      closeSearch();
      setSearchQuery("");
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
      <DialogContent className="max-w-2xl max-h-[80vh] p-0">
        <DialogHeader className="px-6 pt-6 pb-4 border-b">
          <DialogTitle className="text-2xl font-bold">Search Tools</DialogTitle>
          <div className="relative mt-4">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="Search by name, description, or keywords..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onKeyDown={handleKeyDown}
              className="pl-10 h-11"
              autoFocus
              data-testid="input-search-tools"
            />
          </div>
        </DialogHeader>

        <div className="overflow-y-auto max-h-[calc(80vh-180px)] px-6 py-4">
          {filteredTools.length === 0 ? (
            <div className="text-center py-12">
              <Search className="h-12 w-12 text-muted-foreground mx-auto mb-4 opacity-50" />
              <p className="text-lg font-medium text-muted-foreground">No tools found</p>
              <p className="text-sm text-muted-foreground mt-2">
                Try searching with different keywords
              </p>
            </div>
          ) : (
            <div className="space-y-2">
              {filteredTools.map((tool) => {
                const Icon = getToolIcon(tool.icon);
                return (
                  <button
                    key={tool.id}
                    onClick={() => handleToolSelect(tool.path)}
                    className="w-full text-left p-4 rounded-lg border-2 border-border hover:border-primary/50 hover-elevate active-elevate-2 transition-all duration-200 group"
                    data-testid={`button-search-result-${tool.id}`}
                  >
                    <div className="flex items-start gap-4">
                      <div className="h-12 w-12 rounded-lg bg-gradient-to-br from-primary/20 to-primary/5 flex items-center justify-center flex-shrink-0 group-hover:from-primary/30 group-hover:to-primary/10 transition-all">
                        <Icon className="h-6 w-6 text-primary" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1 flex-wrap">
                          <h3 className="font-semibold text-base group-hover:text-primary transition-colors">
                            {tool.name}
                          </h3>
                          <Badge variant="secondary" className="capitalize text-xs">
                            {tool.category}
                          </Badge>
                        </div>
                        <p className="text-sm text-muted-foreground line-clamp-2">
                          {tool.description}
                        </p>
                      </div>
                      <ArrowRight className="h-5 w-5 text-muted-foreground group-hover:text-primary group-hover:translate-x-1 transition-all flex-shrink-0" />
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        <div className="px-6 py-4 border-t bg-muted/30">
          <div className="flex items-center justify-between text-xs text-muted-foreground">
            <span>
              {filteredTools.length} {filteredTools.length === 1 ? "tool" : "tools"} found
            </span>
            <div className="flex items-center gap-4">
              <span className="flex items-center gap-1">
                <kbd className="px-2 py-1 bg-background border rounded text-xs">Enter</kbd>
                to select
              </span>
              <span className="flex items-center gap-1">
                <kbd className="px-2 py-1 bg-background border rounded text-xs">Esc</kbd>
                to close
              </span>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

export function SearchButton({ variant = "default", iconOnly = false }: { variant?: "default" | "ghost" | "outline", iconOnly?: boolean }) {
  const { openSearch } = useSearch();

  if (iconOnly) {
    return (
      <Button
        variant={variant}
        size="icon"
        onClick={openSearch}
        data-testid="button-search"
        aria-label="Search Tools"
      >
        <Search className="h-5 w-5" />
        <span className="sr-only">Search Tools</span>
      </Button>
    );
  }

  return (
    <Button
      variant={variant}
      size="lg"
      onClick={openSearch}
      className="gap-3 px-8 shadow-lg hover:shadow-xl transition-all"
      data-testid="button-search"
    >
      <Search className="h-5 w-5" />
      <span>Search Tools</span>
      <kbd className="hidden md:inline-flex h-6 select-none items-center gap-1 rounded border bg-muted px-2 font-mono text-xs font-medium opacity-100">
        <span className="text-sm">⌘</span>K
      </kbd>
    </Button>
  );
}

