            <div className="p-4 bg-muted rounded-lg">
              <p className="text-sm text-muted-foreground">Percentage Change</p>
              <p className="text-3xl font-bold" data-testid="text-change-result">{calculateIncrease()}%</p>
            </div>
          </CardContent>
        </Card>
      </div>
    </ToolLayout>
  );
}

