import { useState } from "react";
import { useSEO } from "@/lib/seo";
import { ToolLayout } from "@/components/layout/ToolLayout";
import { Calculator } from "lucide-react";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";

export default function CommissionCalculator() {
  const [dealPrice, setDealPrice] = useState<string>("");
  const [commissionRate, setCommissionRate] = useState<string>("2");

  useSEO({
    title: "Commission Calculator | Real Estate Brokerage Calculator | Pixocraft Tools",
    description: "Calculate real estate commission for deals instantly. Works offline and 100% accurate.",
    keywords: "commission calculator, brokerage calculator, real estate commission, property commission",
    canonicalUrl: "https://tools.pixocraft.in/tools/commission-calculator",
  });

  const calculateCommission = () => {
    const price = parseFloat(dealPrice) || 0;
    const rate = parseFloat(commissionRate) || 0;
    return (price * rate / 100).toFixed(2);
  };

  const howItWorks = [
    { step: 1, title: "Enter Deal Price", description: "Input the property or deal value" },
    { step: 2, title: "Set Commission %", description: "Enter your commission rate" },
    { step: 3, title: "Get Result", description: "See commission amount instantly" },
  ];

  const benefits = [
    { icon: <Calculator className="h-5 w-5" />, title: "Instant", description: "Real-time commission calculation" },
    { icon: <Calculator className="h-5 w-5" />, title: "Accurate", description: "100% precise calculations" },
    { icon: <Calculator className="h-5 w-5" />, title: "Property Ready", description: "Perfect for real estate agents" },
  ];

  const faqs = [
    { question: "What commission rate should I use?", answer: "Typical real estate commission is 1-3%, but it varies by agreement." },
    { question: "Can I use this for other commissions?", answer: "Yes! Works for any percentage-based commission calculation." },
    { question: "Is it accurate for large deals?", answer: "Absolutely! It handles any deal size with precision." },
  ];

  return (
    <ToolLayout
      title="Commission Calculator"
      description="Calculate real estate commission for deals instantly. Works offline and 100% accurate."
      icon={<Calculator className="h-8 w-8" />}
      toolId="commission-calculator"
      category="utility"
      howItWorks={howItWorks}
      benefits={benefits}
      faqs={faqs}
    >
      <div className="space-y-6 max-w-2xl mx-auto">
        <div className="space-y-4">
          <Label htmlFor="deal-price" className="text-base font-semibold">Deal Price</Label>
          <Input
            id="deal-price"
            type="number"
            value={dealPrice}
            onChange={(e) => setDealPrice(e.target.value)}
            placeholder="1000000"
            data-testid="input-deal-price"
          />
        </div>

        <div className="space-y-4">
          <Label htmlFor="commission-rate" className="text-base font-semibold">Commission Rate (%)</Label>
          <Input
            id="commission-rate"
            type="number"
            value={commissionRate}
            onChange={(e) => setCommissionRate(e.target.value)}
            placeholder="2"
            step="0.1"
            data-testid="input-commission-rate"
          />
        </div>

        <Card>
          <CardContent className="p-6 space-y-4">
            <div>
              <p className="text-sm text-muted-foreground">Deal Price</p>
              <p className="text-2xl font-bold">${parseFloat(dealPrice || "0").toLocaleString()}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Commission Rate</p>
              <p className="text-2xl font-bold">{commissionRate}%</p>
            </div>
            <div className="pt-4 border-t">
              <p className="text-sm text-muted-foreground">Your Commission</p>
              <p className="text-4xl font-bold text-primary" data-testid="text-commission-result">${parseFloat(calculateCommission()).toLocaleString()}</p>
            </div>
          </CardContent>
        </Card>
      </div>
    </ToolLayout>
  );
}

client/src/pages/tools/FileToBase64.tsx.content:
import { useState } from "react";
import { useSEO } from "@/lib/seo";
import { ToolLayout } from "@/components/layout/ToolLayout";
import { FileCode, Upload, Copy, Download } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";

export default function FileToBase64() {
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [base64Result, setBase64Result] = useState<string>("");
  const { toast } = useToast();

  useSEO({
    title: "File to Base64 Converter | Convert Any File Offline | Pixocraft Tools",
    description: "Convert documents, images & files to Base64 instantly. Secure, offline and lightning fast.",
    keywords: "file to base64, convert file base64, base64 tool, document converter",
    canonicalUrl: "https://tools.pixocraft.in/tools/file-to-base64",
  });

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setBase64Result(base64);
        toast({
          title: "File Converted!",
          description: "Your file has been converted to Base64",
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const copyToClipboard = async () => {
    await navigator.clipboard.writeText(base64Result);
    toast({
      title: "Copied!",
      description: "Base64 code copied to clipboard",
    });
  };

  const downloadAsText = () => {
    const blob = new Blob([base64Result], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.download = 'base64-output.txt';
    link.href = url;
    link.click();
    URL.revokeObjectURL(url);
  };

  const howItWorks = [
    { step: 1, title: "Choose File", description: "Select any file from your device" },
    { step: 2, title: "Auto Convert", description: "File is instantly converted to Base64 format" },
    { step: 3, title: "Copy or Download", description: "Copy to clipboard or download as text file" },
  ];

  const benefits = [
    { icon: <Upload className="h-5 w-5" />, title: "Any File Type", description: "Convert documents, images, PDFs, and more" },
    { icon: <FileCode className="h-5 w-5" />, title: "100% Offline", description: "Files never leave your browser - completely secure" },
    { icon: <Copy className="h-5 w-5" />, title: "Instant Results", description: "Lightning fast conversion in milliseconds" },
  ];

  const faqs = [
    {
      question: "What is Base64 encoding?",
      answer: "Base64 is a way to encode binary data into ASCII text format, making it safe for transmission over text-based protocols.",
    },
    {
      question: "Is my file uploaded to a server?",
      answer: "No. All conversion happens locally in your browser. Your files never leave your device.",
    },
    {
      question: "What file types are supported?",
      answer: "All file types are supported - documents, images, PDFs, videos, archives, and more.",
    },
  ];

  return (
    <ToolLayout
      title="File to Base64 Converter"
      description="Convert documents, images & files to Base64 instantly. Secure, offline and lightning fast."
      icon={<FileCode className="h-8 w-8" />}
      toolId="file-to-base64"
      category="utility"
      howItWorks={howItWorks}
      benefits={benefits}
      faqs={faqs}
    >
      <div className="space-y-6">
        <div className="space-y-4">
          <Label htmlFor="file-upload" className="text-base font-semibold">
            Select File to Convert
          </Label>
          <div className="flex items-center gap-4">
            <input
              id="file-upload"
              type="file"
              onChange={handleFileUpload}
              className="hidden"
              data-testid="input-file-upload"
            />
            <Button
              onClick={() => document.getElementById('file-upload')?.click()}
              size="lg"
              data-testid="button-upload-file"
            >
              <Upload className="mr-2 h-5 w-5" />
              Choose File
            </Button>
            {selectedFile && (
              <span className="text-sm text-muted-foreground">
                {selectedFile.name} ({(selectedFile.size / 1024).toFixed(2)} KB)
              </span>
            )}
          </div>
        </div>

        {base64Result && (
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label className="text-base font-semibold">Base64 Output</Label>
              <div className="flex gap-2">
                <Button
                  onClick={copyToClipboard}
                  variant="outline"
                  data-testid="button-copy-base64"
                >
                  <Copy className="mr-2 h-4 w-4" />
                  Copy
                </Button>
                <Button
                  onClick={downloadAsText}
                  variant="outline"
                  data-testid="button-download-base64"
                >
                  <Download className="mr-2 h-4 w-4" />
                  Download
                </Button>
              </div>
            </div>
            <Textarea
              value={base64Result}
              readOnly
              className="font-mono text-sm min-h-[300px]"
              data-testid="textarea-base64-output"
            />
            <p className="text-sm text-muted-foreground">
              Length: {base64Result.length} characters
            </p>
          </div>
        )}
      </div>
    </ToolLayout>
  );
}

client/src/pages/tools/UTMBuilder.tsx.content:
import { useState } from "react";
import { useSEO } from "@/lib/seo";
import { ToolLayout } from "@/components/layout/ToolLayout";
import { Link, Copy } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { useToast } from "@/hooks/use-toast";

export default function UTMBuilder() {
  const [baseUrl, setBaseUrl] = useState<string>("");
  const [source, setSource] = useState<string>("");
  const [medium, setMedium] = useState<string>("");
  const [campaign, setCampaign] = useState<string>("");
  const [term, setTerm] = useState<string>("");
  const [content, setContent] = useState<string>("");
  const [generatedUrl, setGeneratedUrl] = useState<string>("");
  const { toast } = useToast();

  useSEO({
    title: "UTM Builder Online | Create Trackable Links Easily | Pixocraft Tools",
    description: "Generate UTM tracking links for Google Analytics. Free, fast and 100% offline.",
    keywords: "utm builder, utm generator, tracking link creator, google analytics, utm parameters",
    canonicalUrl: "https://tools.pixocraft.in/tools/utm-builder",
  });

  const buildUTMUrl = () => {
    if (!baseUrl || !source || !medium || !campaign) {
      toast({
        title: "Missing Required Fields",
        description: "Please fill in URL, Source, Medium, and Campaign",
        variant: "destructive",
      });
      return;
    }

    const params = new URLSearchParams();
    params.append('utm_source', source);
    params.append('utm_medium', medium);
    params.append('utm_campaign', campaign);
    if (term) params.append('utm_term', term);
    if (content) params.append('utm_content', content);

    const url = baseUrl.includes('?') 
      ? `${baseUrl}&${params.toString()}`
      : `${baseUrl}?${params.toString()}`;

    setGeneratedUrl(url);
    toast({
      title: "UTM Link Generated!",
      description: "Your tracking link is ready",
    });
  };

  const copyToClipboard = async () => {
    await navigator.clipboard.writeText(generatedUrl);
    toast({
      title: "Copied!",
      description: "UTM link copied to clipboard",
    });
  };

  const howItWorks = [
    { step: 1, title: "Enter URL", description: "Provide your website URL" },
    { step: 2, title: "Add UTM Parameters", description: "Fill in source, medium, campaign, and optional fields" },
    { step: 3, title: "Generate & Track", description: "Use the link in your campaigns and track in Google Analytics" },
  ];

  const benefits = [
    { icon: <Link className="h-5 w-5" />, title: "Track Everything", description: "Monitor campaign performance in Google Analytics" },
    { icon: <Link className="h-5 w-5" />, title: "100% Offline", description: "Generate UTM links without sending data anywhere" },
    { icon: <Copy className="h-5 w-5" />, title: "Marketing Ready", description: "Perfect for ads, emails, and social media" },
  ];

  const faqs = [
    {
      question: "What are UTM parameters?",
      answer: "UTM parameters are tags added to URLs to track the effectiveness of marketing campaigns in analytics tools like Google Analytics.",
    },
    {
      question: "Which parameters are required?",
      answer: "Source, Medium, and Campaign are required. Term and Content are optional for more detailed tracking.",
    },
    {
      question: "Can I track social media posts?",
