                        </div>
                      </SelectItem>
                      <SelectItem value="divide" data-testid="option-divide">
                        <div className="flex items-center gap-2">
                          <Divide className="h-4 w-4" />÷
                        </div>
                      </SelectItem>
                    </SelectContent>
                  </Select>

                  <div className="flex items-center gap-2">
                    <div className="flex flex-col gap-2 items-center">
                      <Input
                        type="number"
