        toast({
          title: "Invalid Input",
          description: "Please enter a valid number",
          variant: "destructive",
        });
        return;
      }
      if (num < 1 || num > 3999) {
        toast({
          title: "Out of Range",
          description: "Number must be between 1 and 3999",
          variant: "destructive",
        });
        return;
      }
      const roman = numberToRoman(num);
      setNumberToRomanResult(roman);
    } catch (error) {
      toast({
