        { step: 3, title: "Copy & Share", description: "Use rotated text anywhere!" },
      ]}
      benefits={[
        { icon: <RotateCw className="h-6 w-6 text-primary" />, title: "Fun Effects", description: "Create unique text transformations." },
      ]}
