    if (code >= 65 && code <= 90) return String.fromCharCode(code + 120055);
    if (code >= 97 && code <= 122) return String.fromCharCode(code + 120049);
    if (code >= 48 && code <= 57) return String.fromCharCode(code + 120734);
    return c;
  }).join(''),
};

