import { useState } from "react";
import { useSEO, StructuredData, generateFAQSchema, type FAQItem } from "@/lib/seo";
import { ToolLayout } from "@/components/layout/ToolLayout";
import { User, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Link } from "wouter";
import { hindiNames } from "@/lib/random-data";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

export default function RandomHindiName() {
  const [name, setName] = useState<string | null>(null);
  const [gender, setGender] = useState<'male' | 'female'>('male');

  useSEO({
    title: "Random Hindi Name Generator | Indian Names | Pixocraft Tools",
    description: "Generate offline Indian names for characters, ideas, etc. Perfect for writers, game developers, and creative projects.",
    keywords: "hindi name generator, indian names, random name generator",
    canonicalUrl: "https://tools.pixocraft.in/tools/random-hindi-name",
  });

  const generateName = () => {
    const names = gender === 'male' ? hindiNames.male : hindiNames.female;
    const randomIndex = Math.floor(Math.random() * names.length);
    setName(names[randomIndex]);
  };

  const howItWorks = [
    { step: 1, title: "Choose Gender", description: "Select male or female" },
    { step: 2, title: "Click Generate", description: "Get random Indian name" },
    { step: 3, title: "Use It", description: "Perfect for characters & stories" },
  ];

  const benefits = [
    { icon: <User className="h-5 w-5" />, title: "Modern Names", description: "Popular Indian names" },
    { icon: <User className="h-5 w-5" />, title: "Both Genders", description: "Male and female names" },
    { icon: <User className="h-5 w-5" />, title: "Creative Use", description: "Great for writing" },
    { icon: <User className="h-5 w-5" />, title: "Offline", description: "Works without internet" },
  ];

  const faqItems: FAQItem[] = [
    {
      question: "How many names are available?",
      answer: "We have 15+ popular male names and 15+ popular female names, totaling 30+ modern Indian names."
    }
  ];

  const faqSchema = generateFAQSchema(faqItems);
  const faqs = faqItems.map(item => ({ question: item.question, answer: item.answer }));

  return (
    <>
      <StructuredData data={faqSchema} />
      <ToolLayout
        title="Random Hindi Name Generator"
        description="Click → get names"
        icon={<User className="h-8 w-8" />}
        toolId="random-hindi-name"
        category="generator"
        howItWorks={howItWorks}
        benefits={benefits}
        faqs={faqs}
      >
        <div className="mb-8 text-sm text-muted-foreground max-w-4xl mx-auto">
          <Link href="/" className="hover:text-foreground">Home</Link>
          {" / "}
          <Link href="/tools" className="hover:text-foreground">Tools</Link>
          {" / "}
          <span className="text-foreground">Random Hindi Name</span>
        </div>

        <div className="space-y-6 max-w-2xl mx-auto">
          <Tabs value={gender} onValueChange={(v) => setGender(v as 'male' | 'female')} className="w-full">
            <TabsList className="grid w-full grid-cols-2">
              <TabsTrigger value="male">Male Names</TabsTrigger>
              <TabsTrigger value="female">Female Names</TabsTrigger>
            </TabsList>
            <TabsContent value={gender} className="mt-6">
              <Button
                onClick={generateName}
                size="lg"
                className="w-full"
                data-testid="button-generate"
              >
                <RefreshCw className="mr-2 h-5 w-5" />
                Generate {gender === 'male' ? 'Male' : 'Female'} Name
              </Button>
            </TabsContent>
          </Tabs>

          {name && (
            <Card>
              <CardContent className="p-8 text-center">
                <h3 className="text-5xl font-bold" data-testid="text-name">{name}</h3>
              </CardContent>
            </Card>
          )}
        </div>
      </ToolLayout>
    </>
  );
}

client/src/pages/tools/PrimeNumberChecke.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Hash, CheckCircle, XCircle } from "lucide-react";
import { useSEO, StructuredData, generateFAQSchema, type FAQItem } from "@/lib/seo";
import { Link } from "wouter";
import { Badge } from "@/components/ui/badge";
import { isPrime } from "@/lib/math-utils";

export default function PrimeNumberChecker() {
  const [number, setNumber] = useState("");
  const [result, setResult] = useState<{ isPrime: boolean; message: string } | null>(null);

  useSEO({
    title: "Prime Number Checker | Check If Number Is Prime | Pixocraft Tools",
    description: "Instantly check whether a number is prime or composite. Fully offline prime number verification tool. Fast, accurate, and supports large numbers.",
    keywords: "prime number checker, is prime tool, check prime number, prime or composite",
    canonicalUrl: "https://tools.pixocraft.in/tools/prime-number-checker",
  });

  const checkPrime = () => {
    const num = parseInt(number);
    if (isNaN(num)) {
      setResult({ isPrime: false, message: "Please enter a valid number" });
      return;
    }

    const prime = isPrime(num);
    setResult({
      isPrime: prime,
      message: prime 
        ? `${num} is a prime number` 
        : `${num} is not a prime number (composite)`
    });
  };

  const faqItems: FAQItem[] = [
    {
      question: "Large numbers supported?",
      answer: "Yes. Our prime number checker can efficiently verify numbers up to millions. The algorithm uses optimized mathematical techniques to check primality quickly."
    },
    {
      question: "What is a prime number?",
      answer: "A prime number is a natural number greater than 1 that has no positive divisors other than 1 and itself. For example, 2, 3, 5, 7, 11 are prime numbers."
    },
    {
      question: "Is 1 a prime number?",
      answer: "No, 1 is not considered a prime number. By definition, a prime number must have exactly two distinct positive divisors: 1 and itself. Since 1 only has one divisor, it's not prime."
    }
  ];

  const faqSchema = generateFAQSchema(faqItems);

  return (
    <>
      <StructuredData data={faqSchema} />
      <div className="min-h-screen py-12">
        <div className="container mx-auto px-4 max-w-7xl">
          <div className="mb-8 text-sm text-muted-foreground">
            <Link href="/" className="hover:text-foreground">Home</Link>
            {" / "}
            <Link href="/tools" className="hover:text-foreground">Tools</Link>
            {" / "}
            <span className="text-foreground">Prime Number Checker</span>
          </div>

          <div className="text-center space-y-4 mb-12">
            <div className="flex items-center justify-center gap-3 mb-4">
              <div className="h-16 w-16 rounded-xl bg-primary/10 flex items-center justify-center">
                <Hash className="h-8 w-8 text-primary" />
              </div>
            </div>
            <h1 className="text-4xl md:text-5xl font-bold">Prime Number Checker</h1>
            <p className="text-xl text-muted-foreground max-w-2xl mx-auto">
              Enter number → check prime instantly
            </p>
            <div className="flex flex-wrap items-center justify-center gap-2">
              <Badge variant="secondary">Fast</Badge>
              <Badge variant="secondary">Accurate</Badge>
              <Badge variant="secondary">Offline</Badge>
            </div>
          </div>

          <div className="max-w-2xl mx-auto mb-16">
            <Card>
              <CardHeader>
                <CardTitle>Check Prime Number</CardTitle>
                <CardDescription>
                  Enter any number to check if it's prime
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                <div className="space-y-2">
                  <Label>Enter Number</Label>
                  <Input
                    type="number"
                    value={number}
                    onChange={(e) => setNumber(e.target.value)}
                    placeholder="e.g., 17"
                    data-testid="input-number"
                  />
                </div>

                <Button onClick={checkPrime} className="w-full" data-testid="button-check">
                  Check Prime
                </Button>

                {result && (
                  <Card className={result.isPrime ? "bg-chart-3/10" : "bg-destructive/10"}>
                    <CardContent className="p-6">
                      <div className="flex items-center gap-3">
                        {result.isPrime ? (
                          <CheckCircle className="h-8 w-8 text-chart-3" />
                        ) : (
                          <XCircle className="h-8 w-8 text-destructive" />
                        )}
