  };

  const processWatermark = async () => {
    if (!file) return;

    setLoading(true);
    try {
      const result = await attemptWatermarkRemoval(file);
      setProcessedFile(result);
      toast({
        title: "Processed",
        description: "PDF processed. Note: Complete watermark removal may not be possible.",
