export default function AudioToMP3() {
  const [file, setFile] = useState<File | null>(null);
  const [mp3Blob, setMp3Blob] = useState<Blob | null>(null);
  const [converting, setConverting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();

  useSEO({
    title: "Free Audio to MP3 Converter Online - Convert Audio to MP3 | Pixocraft Tools",
    description: "Convert audio files to MP3 format online for free. Transform WAV, OGG, FLAC to MP3 instantly. Fast, secure, works offline in your browser.",
    keywords: "audio to mp3 converter, convert audio to mp3 free, wav to mp3, ogg to mp3, audio converter online",
    canonicalUrl: "https://tools.pixocraft.in/tools/audio-to-mp3",
  });

  const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = event.target.files?.[0];
    if (selectedFile?.type.startsWith('audio/')) {
      setFile(selectedFile);
      setMp3Blob(null);
    } else {
      toast({ title: "Invalid File", description: "Please select an audio file", variant: "destructive" });
    }
  };

  const convert = async () => {
    if (!file) return;
    setConverting(true);
    try {
      const result = await convertAudioToMP3(file);
      setMp3Blob(result);
      toast({ title: "Success!", description: "Audio converted to MP3" });
    } catch (error) {
      toast({ title: "Error", description: "Failed to convert audio", variant: "destructive" });
    } finally {
      setConverting(false);
    }
  };

  const download = () => {
    if (mp3Blob) {
      const url = URL.createObjectURL(mp3Blob);
      const link = document.createElement("a");
      link.download = file?.name.replace(/\.[^.]+$/, '.mp3') || "output.mp3";
      link.href = url;
      link.click();
      URL.revokeObjectURL(url);
    }
  };

  return (
    <>
      <StructuredData data={generateFAQSchema([{question: "What audio formats can be converted to MP3?", answer: "The tool supports most audio formats including WAV, OGG, FLAC, M4A, and more. All conversion happens in your browser for complete privacy."}])} />
      <div className="min-h-screen py-12">
